#!/usr/bin/env python3
import ast
import sys
import random
import string

class VariableRenamer(ast.NodeTransformer):
    def __init__(self, mapping):
        self.mapping = mapping

    def visit_Name(self, node):
        if node.id in self.mapping:
            node.id = self.mapping[node.id]
        return node

    def visit_FunctionDef(self, node):
        if node.name in self.mapping:
            node.name = self.mapping[node.name]
        self.generic_visit(node)
        return node

class DeadCodeInjector(ast.NodeTransformer):
    def __init__(self, injection_rate=0.3):
        self.injection_rate = injection_rate

    def generate_opaque_predicate(self):
        patterns = [
            ast.If(
                test=ast.Compare(
                    left=ast.Constant(value=1),
                    ops=[ast.Eq()],
                    comparators=[ast.Constant(value=2)]
                ),
                body=[ast.Pass()],
                orelse=[]
            ),
            ast.For(
                target=ast.Name(id='_dead', ctx=ast.Store()),
                iter=ast.Call(
                    func=ast.Name(id='range', ctx=ast.Load()),
                    args=[ast.Constant(value=0)],
                    keywords=[]
                ),
                body=[ast.Pass()],
                orelse=[]
            ),
            ast.While(
                test=ast.Constant(value=False),
                body=[ast.Break()],
                orelse=[]
            )
        ]
        return random.choice(patterns)

    def visit_FunctionDef(self, node):
        new_body = []
        for stmt in node.body:
            if random.random() < self.injection_rate:
                new_body.append(self.generate_opaque_predicate())
            new_body.append(self.visit(stmt))
        node.body = new_body
        return node

class StringSplitter(ast.NodeTransformer):
    def visit_Constant(self, node):
        if isinstance(node.value, str) and len(node.value) > 10:
            mid = len(node.value) // 2
            part1 = node.value[:mid]
            part2 = node.value[mid:]
            return ast.BinOp(
                left=ast.Constant(value=part1),
                op=ast.Add(),
                right=ast.Constant(value=part2)
            )
        return node

class ControlFlowFlattener(ast.NodeTransformer):
    def __init__(self):
        self.state_counter = 0

    def flatten_statements(self, stmts):
        if len(stmts) < 3:
            return stmts

        state_var = '_state_' + ''.join(random.choices(string.ascii_lowercase, k=4))
        cases = {}

        for i, stmt in enumerate(stmts):
            cases[i] = stmt

        switch_body = []
        for state, stmt in cases.items():
            next_state = state + 1 if state < len(stmts) - 1 else -1

            case_block = ast.If(
                test=ast.Compare(
                    left=ast.Name(id=state_var, ctx=ast.Load()),
                    ops=[ast.Eq()],
                    comparators=[ast.Constant(value=state)]
                ),
                body=[
                    stmt,
                    ast.Assign(
                        targets=[ast.Name(id=state_var, ctx=ast.Store())],
                        value=ast.Constant(value=next_state)
                    )
                ],
                orelse=[]
            )
            switch_body.append(case_block)

        return [
            ast.Assign(
                targets=[ast.Name(id=state_var, ctx=ast.Store())],
                value=ast.Constant(value=0)
            ),
            ast.While(
                test=ast.Compare(
                    left=ast.Name(id=state_var, ctx=ast.Load()),
                    ops=[ast.GtE()],
                    comparators=[ast.Constant(value=0)]
                ),
                body=switch_body,
                orelse=[]
            )
        ]

def generate_var_mapping(code_str):
    tree = ast.parse(code_str)

    names = set()
    for node in ast.walk(tree):
        if isinstance(node, ast.Name):
            if not node.id.startswith('_') and node.id not in dir(__builtins__):
                names.add(node.id)

    mapping = {}
    for name in names:
        new_name = 'var_' + ''.join(random.choices(string.ascii_lowercase + string.digits, k=8))
        mapping[name] = new_name

    return mapping

def transform_code(code_str, passes=3):
    transformers = [
        ('dead_code', DeadCodeInjector(injection_rate=0.2)),
        ('string_split', StringSplitter()),
    ]

    tree = ast.parse(code_str)

    var_mapping = generate_var_mapping(code_str)
    renamer = VariableRenamer(var_mapping)
    tree = renamer.visit(tree)

    for pass_num in range(passes):
        for name, transformer in transformers:
            tree = transformer.visit(tree)
        ast.fix_missing_locations(tree)

    return ast.unparse(tree), var_mapping

def main():
    sample_code = '''
def calculate_checksum(data):
    result = 0
    for byte in data:
        result = (result + byte) % 256
    return result

def validate_input(value):
    if value < 0:
        return False
    if value > 1000:
        return False
    return True

data = [1, 2, 3, 4, 5]
checksum = calculate_checksum(data)
print(checksum)
'''

    print("[*] Original Code:")
    print("=" * 70)
    print(sample_code)
    print("=" * 70)

    print("\n[*] Transforming code through 3 passes...")
    transformed, mapping = transform_code(sample_code, passes=3)

    print("\n[*] Variable Mapping:")
    for old, new in sorted(mapping.items()):
        print("    %s -> %s" % (old, new))

    print("\n[*] Transformed Code:")
    print("=" * 70)
    print(transformed)
    print("=" * 70)

    print("\n[*] Size comparison:")
    print("    Original: %d bytes" % len(sample_code))
    print("    Transformed: %d bytes" % len(transformed))
    print("    Ratio: %.2fx" % (len(transformed) / float(len(sample_code))))

    print("\n[*] Validating transformed code execution...")
    try:
        namespace_orig = {}
        exec(sample_code, namespace_orig)
        orig_checksum = namespace_orig.get('checksum')

        namespace_trans = {}
        exec(transformed, namespace_trans)

        trans_checksum = None
        for key, value in namespace_trans.items():
            if isinstance(value, int) and value == orig_checksum:
                trans_checksum = value
                break

        if orig_checksum == trans_checksum:
            print("[+] Semantic equivalence verified (checksum: %s)" % orig_checksum)
        else:
            print("[-] Semantic difference detected")
            return 1
    except Exception as e:
        print("[-] Execution failed: %s" % str(e))
        return 1

    print("\n[*] Polymorphic transformation complete")
    return 0

if __name__ == '__main__':
    sys.exit(main())

