#!/usr/bin/env python3
import sys
import os
import platform
import subprocess
import struct
import socket

def check_cpuid_hypervisor():
    try:
        if platform.system() == 'Linux':
            with open('/proc/cpuinfo', 'r') as f:
                cpuinfo = f.read()
                if 'hypervisor' in cpuinfo.lower():
                    return True, 'hypervisor flag in cpuinfo'
                if any(vendor in cpuinfo.lower() for vendor in ['vmware', 'virtualbox', 'kvm', 'xen', 'qemu']):
                    return True, 'VM vendor in cpuinfo'
        elif platform.system() == 'Windows':
            try:
                import ctypes
                cpuid = ctypes.CDLL('msvcrt').cpuid
                result = (ctypes.c_uint * 4)()
                cpuid(1, result)
                if result[2] & (1 << 31):
                    return True, 'CPUID hypervisor bit set'
            except:
                pass
    except Exception as e:
        return None, 'check failed: %s' % str(e)

    return False, 'no hypervisor detected'

def check_smbios_dmi():
    indicators = []

    vm_vendors = [
        'vmware', 'virtualbox', 'vbox', 'qemu', 'kvm', 'xen',
        'microsoft corporation', 'parallels', 'virtual', 'innotek'
    ]

    try:
        if platform.system() == 'Linux':
            dmi_paths = [
                '/sys/class/dmi/id/product_name',
                '/sys/class/dmi/id/sys_vendor',
                '/sys/class/dmi/id/bios_vendor',
                '/sys/class/dmi/id/board_vendor',
                '/sys/class/dmi/id/chassis_vendor'
            ]

            for path in dmi_paths:
                try:
                    with open(path, 'r') as f:
                        value = f.read().strip().lower()
                        for vendor in vm_vendors:
                            if vendor in value:
                                indicators.append('%s=%s' % (os.path.basename(path), value))
                                break
                except:
                    continue

        elif platform.system() == 'Windows':
            wmic_queries = [
                'bios get manufacturer',
                'computersystem get manufacturer',
                'computersystem get model'
            ]

            for query in wmic_queries:
                try:
                    result = subprocess.check_output('wmic %s' % query,
                                                     shell=True,
                                                     stderr=subprocess.DEVNULL,
                                                     timeout=5).decode().lower()
                    for vendor in vm_vendors:
                        if vendor in result:
                            indicators.append(query.split()[0])
                            break
                except:
                    continue

    except Exception as e:
        return None, [], 'check failed: %s' % str(e)

    detected = len(indicators) > 0
    reason = '%d SMBIOS indicators' % len(indicators) if detected else 'clean SMBIOS'
    return detected, indicators, reason

def check_mac_addresses():
    vm_oui_prefixes = {
        '00:05:69': 'VMware',
        '00:0c:29': 'VMware',
        '00:1c:14': 'VMware',
        '00:50:56': 'VMware',
        '08:00:27': 'VirtualBox',
        '00:16:3e': 'Xen',
        '00:1c:42': 'Parallels',
        '00:15:5d': 'Hyper-V',
        '52:54:00': 'QEMU/KVM'
    }

    found_vms = []

    try:
        if platform.system() == 'Linux':
            net_path = '/sys/class/net'
            if os.path.exists(net_path):
                for iface in os.listdir(net_path):
                    addr_file = os.path.join(net_path, iface, 'address')
                    try:
                        with open(addr_file, 'r') as f:
                            mac = f.read().strip().upper()
                            prefix = ':'.join(mac.split(':')[:3])
                            if prefix in vm_oui_prefixes:
                                found_vms.append('%s (%s)' % (mac, vm_oui_prefixes[prefix]))
                    except:
                        continue

        elif platform.system() == 'Windows':
            try:
                result = subprocess.check_output('getmac /fo csv /nh',
                                                shell=True,
                                                stderr=subprocess.DEVNULL,
                                                timeout=5).decode()
                for line in result.split('\n'):
                    if ',' in line:
                        parts = line.split(',')
                        if len(parts) >= 2:
                            mac = parts[1].strip('"').upper()
                            prefix = '-'.join(mac.split('-')[:3]).replace('-', ':')
                            if prefix in vm_oui_prefixes:
                                found_vms.append('%s (%s)' % (mac, vm_oui_prefixes[prefix]))
            except:
                pass

    except Exception as e:
        return None, [], 'check failed: %s' % str(e)

    detected = len(found_vms) > 0
    reason = 'found %d VM MACs' % len(found_vms) if detected else 'no VM MAC addresses'
    return detected, found_vms, reason

def check_disk_size():
    try:
        if platform.system() == 'Linux':
            result = subprocess.check_output(['df', '-BG', '/'],
                                            stderr=subprocess.DEVNULL,
                                            timeout=5).decode()
            lines = result.strip().split('\n')
            if len(lines) >= 2:
                parts = lines[1].split()
                size_str = parts[1].rstrip('G')
                size_gb = int(size_str)

                suspicious = size_gb < 80
                reason = 'disk size %dGB (suspicious)' % size_gb if suspicious else 'disk size %dGB (normal)' % size_gb
                return suspicious, size_gb, reason

        elif platform.system() == 'Windows':
            import ctypes
            free_bytes = ctypes.c_ulonglong(0)
            total_bytes = ctypes.c_ulonglong(0)
            ctypes.windll.kernel32.GetDiskFreeSpaceExW(
                'C:\\', None, ctypes.byref(total_bytes), ctypes.byref(free_bytes))
            size_gb = total_bytes.value // (1024 ** 3)

            suspicious = size_gb < 80
            reason = 'disk size %dGB (suspicious)' % size_gb if suspicious else 'disk size %dGB (normal)' % size_gb
            return suspicious, size_gb, reason

    except Exception as e:
        return None, 0, 'check failed: %s' % str(e)

    return False, 0, 'unable to determine'

def check_vm_processes():
    vm_processes = [
        'vmtoolsd', 'vmwareuser', 'vmacthlp', 'vmwaretray', 'vmwareservice',
        'vboxservice', 'vboxtray', 'vboxclient',
        'qemu-ga', 'qemu-system',
        'xenservice',
        'prltools', 'prl_cc', 'prl_tools'
    ]

    found = []

    try:
        if platform.system() == 'Linux':
            result = subprocess.check_output(['ps', 'aux'],
                                            stderr=subprocess.DEVNULL,
                                            timeout=5).decode().lower()
            for proc in vm_processes:
                if proc.lower() in result:
                    found.append(proc)

        elif platform.system() == 'Windows':
            result = subprocess.check_output('tasklist',
                                            shell=True,
                                            stderr=subprocess.DEVNULL,
                                            timeout=5).decode().lower()
            for proc in vm_processes:
                if proc.lower() in result:
                    found.append(proc)

    except Exception as e:
        return None, [], 'check failed: %s' % str(e)

    detected = len(found) > 0
    reason = 'found %d VM processes' % len(found) if detected else 'no VM processes'
    return detected, found, reason

def main():
    print("[*] VM Detection Suite")
    print("=" * 70)

    print("\n[*] CPUID Hypervisor Check")
    detected, reason = check_cpuid_hypervisor()
    status = 'DETECTED' if detected else 'CLEAN' if detected is False else 'UNAVAILABLE'
    print("    [%s] %s" % (status, reason))

    print("\n[*] SMBIOS/DMI Check")
    detected, indicators, reason = check_smbios_dmi()
    status = 'DETECTED' if detected else 'CLEAN' if detected is False else 'UNAVAILABLE'
    print("    [%s] %s" % (status, reason))
    if indicators:
        for ind in indicators[:5]:
            print("        - %s" % ind)

    print("\n[*] MAC Address OUI Check")
    detected, macs, reason = check_mac_addresses()
    status = 'DETECTED' if detected else 'CLEAN' if detected is False else 'UNAVAILABLE'
    print("    [%s] %s" % (status, reason))
    if macs:
        for mac in macs[:5]:
            print("        - %s" % mac)

    print("\n[*] Disk Size Check")
    detected, size, reason = check_disk_size()
    status = 'SUSPICIOUS' if detected else 'CLEAN' if detected is False else 'UNAVAILABLE'
    print("    [%s] %s" % (status, reason))

    print("\n[*] VM Process Check")
    detected, procs, reason = check_vm_processes()
    status = 'DETECTED' if detected else 'CLEAN' if detected is False else 'UNAVAILABLE'
    print("    [%s] %s" % (status, reason))
    if procs:
        for proc in procs[:5]:
            print("        - %s" % proc)

    print("\n" + "=" * 70)
    print("[*] VM detection scan complete")

    return 0

if __name__ == '__main__':
    sys.exit(main())

