#!/usr/bin/env python3
import sys
import os
import time
import platform
import ctypes

def check_timing_differential():
    baseline_samples = []
    for _ in range(50):
        start = time.perf_counter()
        dummy = sum(range(1000))
        end = time.perf_counter()
        baseline_samples.append(end - start)

    baseline_avg = sum(baseline_samples) / len(baseline_samples)

    test_samples = []
    for _ in range(50):
        start = time.perf_counter()
        dummy = sum(range(1000))
        end = time.perf_counter()
        test_samples.append(end - start)

    test_avg = sum(test_samples) / len(test_samples)

    deviation = abs(test_avg - baseline_avg) / baseline_avg

    suspicious = deviation > 0.5

    return {
        'test': 'timing_differential',
        'baseline_avg': baseline_avg,
        'test_avg': test_avg,
        'deviation': deviation,
        'suspicious': suspicious,
        'reason': 'high timing deviation (%.1f%%)' % (deviation * 100) if suspicious else 'normal timing'
    }

def check_debugger_present_windows():
    if platform.system() != 'Windows':
        return {
            'test': 'debugger_present',
            'available': False,
            'reason': 'Windows only'
        }

    try:
        kernel32 = ctypes.windll.kernel32

        is_debugged = kernel32.IsDebuggerPresent()

        process_handle = kernel32.GetCurrentProcess()
        debug_port = ctypes.c_ulong(0)

        nt_status = ctypes.windll.ntdll.NtQueryInformationProcess(
            process_handle,
            7,
            ctypes.byref(debug_port),
            ctypes.sizeof(debug_port),
            None
        )

        port_detected = debug_port.value != 0

        detected = is_debugged or port_detected

        reasons = []
        if is_debugged:
            reasons.append('IsDebuggerPresent=True')
        if port_detected:
            reasons.append('DebugPort=0x%x' % debug_port.value)

        return {
            'test': 'debugger_present',
            'available': True,
            'is_debugger_present': is_debugged,
            'debug_port': debug_port.value,
            'suspicious': detected,
            'reason': ', '.join(reasons) if reasons else 'no debugger detected'
        }

    except Exception as e:
        return {
            'test': 'debugger_present',
            'available': False,
            'reason': 'check failed: %s' % str(e)
        }

def check_heap_flags_windows():
    if platform.system() != 'Windows':
        return {
            'test': 'heap_flags',
            'available': False,
            'reason': 'Windows only'
        }

    try:
        kernel32 = ctypes.windll.kernel32
        ntdll = ctypes.windll.ntdll

        heap = kernel32.GetProcessHeap()

        class PROCESS_HEAP_ENTRY(ctypes.Structure):
            _fields_ = [
                ('lpData', ctypes.c_void_p),
                ('cbData', ctypes.c_ulong),
                ('cbOverhead', ctypes.c_byte),
                ('iRegionIndex', ctypes.c_byte),
                ('wFlags', ctypes.c_ushort),
            ]

        peb_base_address = ctypes.c_void_p()
        ntdll.NtQueryInformationProcess(
            kernel32.GetCurrentProcess(),
            0,
            ctypes.byref(peb_base_address),
            ctypes.sizeof(peb_base_address),
            None
        )

        if peb_base_address.value:
            flags_offset = 0x68 if ctypes.sizeof(ctypes.c_void_p) == 8 else 0x68
            flags = ctypes.c_ulong.from_address(peb_base_address.value + flags_offset).value

            debugger_flags = flags & 0x70
            suspicious = debugger_flags != 0

            return {
                'test': 'heap_flags',
                'available': True,
                'flags': flags,
                'debugger_flags': debugger_flags,
                'suspicious': suspicious,
                'reason': 'debugger heap flags (0x%x)' % debugger_flags if suspicious else 'normal heap flags'
            }

    except Exception as e:
        pass

    return {
        'test': 'heap_flags',
        'available': False,
        'reason': 'unable to read heap flags'
    }

def check_ptrace_linux():
    if platform.system() != 'Linux':
        return {
            'test': 'ptrace',
            'available': False,
            'reason': 'Linux only'
        }

    try:
        status_path = '/proc/self/status'
        with open(status_path, 'r') as f:
            for line in f:
                if line.startswith('TracerPid:'):
                    tracer_pid = int(line.split(':')[1].strip())
                    traced = tracer_pid != 0

                    return {
                        'test': 'ptrace',
                        'available': True,
                        'tracer_pid': tracer_pid,
                        'suspicious': traced,
                        'reason': 'TracerPid=%d (debugger attached)' % tracer_pid if traced else 'not traced'
                    }

    except Exception as e:
        return {
            'test': 'ptrace',
            'available': False,
            'reason': 'check failed: %s' % str(e)
        }

    return {
        'test': 'ptrace',
        'available': False,
        'reason': 'unable to read status'
    }

def check_parent_process():
    try:
        ppid = os.getppid()

        if platform.system() == 'Linux':
            try:
                with open('/proc/%d/comm' % ppid, 'r') as f:
                    parent_name = f.read().strip().lower()
            except:
                parent_name = 'unknown'
        elif platform.system() == 'Windows':
            import subprocess
            try:
                result = subprocess.check_output(
                    'wmic process where processid=%d get name' % ppid,
                    shell=True,
                    stderr=subprocess.DEVNULL,
                    timeout=5
                ).decode()
                lines = result.strip().split('\n')
                parent_name = lines[1].strip().lower() if len(lines) > 1 else 'unknown'
            except:
                parent_name = 'unknown'
        else:
            parent_name = 'unknown'

        debugger_parents = ['gdb', 'lldb', 'windbg', 'x64dbg', 'ollydbg', 'ida', 'idaq', 'python']

        suspicious = any(dbg in parent_name for dbg in debugger_parents)

        return {
            'test': 'parent_process',
            'available': True,
            'ppid': ppid,
            'parent_name': parent_name,
            'suspicious': suspicious,
            'reason': 'suspicious parent (%s)' % parent_name if suspicious else 'normal parent'
        }

    except Exception as e:
        return {
            'test': 'parent_process',
            'available': False,
            'reason': 'check failed: %s' % str(e)
        }

def check_int_scan():
    start = time.perf_counter()
    iterations = 100000

    for i in range(iterations):
        dummy = i * 2

    elapsed = time.perf_counter() - start

    expected_min = iterations * 0.000001

    suspicious = elapsed > (expected_min * 10)

    return {
        'test': 'instruction_timing',
        'iterations': iterations,
        'elapsed': elapsed,
        'expected_min': expected_min,
        'suspicious': suspicious,
        'reason': 'abnormal execution time (%.6fs)' % elapsed if suspicious else 'normal execution time'
    }

def main():
    print("[*] Anti-Debugging Detection Suite")
    print("=" * 70)

    print("\n[*] Timing Differential Analysis")
    result = check_timing_differential()
    status = 'SUSPICIOUS' if result['suspicious'] else 'CLEAN'
    print("    [%s] %s" % (status, result['reason']))
    print("        Baseline: %.9fs" % result['baseline_avg'])
    print("        Test: %.9fs" % result['test_avg'])

    if platform.system() == 'Windows':
        print("\n[*] Windows Debugger Detection")
        result = check_debugger_present_windows()
        if result['available']:
            status = 'DETECTED' if result['suspicious'] else 'CLEAN'
            print("    [%s] %s" % (status, result['reason']))
        else:
            print("    [N/A] %s" % result['reason'])

        print("\n[*] Windows Heap Flags")
        result = check_heap_flags_windows()
        if result['available']:
            status = 'SUSPICIOUS' if result['suspicious'] else 'CLEAN'
            print("    [%s] %s" % (status, result['reason']))
        else:
            print("    [N/A] %s" % result['reason'])

    if platform.system() == 'Linux':
        print("\n[*] Linux ptrace Detection")
        result = check_ptrace_linux()
        if result['available']:
            status = 'DETECTED' if result['suspicious'] else 'CLEAN'
            print("    [%s] %s" % (status, result['reason']))
        else:
            print("    [N/A] %s" % result['reason'])

    print("\n[*] Parent Process Analysis")
    result = check_parent_process()
    if result['available']:
        status = 'SUSPICIOUS' if result['suspicious'] else 'CLEAN'
        print("    [%s] %s" % (status, result['reason']))
        print("        PPID: %d" % result['ppid'])
        print("        Name: %s" % result['parent_name'])
    else:
        print("    [N/A] %s" % result['reason'])

    print("\n[*] Instruction Timing Scan")
    result = check_int_scan()
    status = 'SUSPICIOUS' if result['suspicious'] else 'CLEAN'
    print("    [%s] %s" % (status, result['reason']))
    print("        Iterations: %d" % result['iterations'])
    print("        Elapsed: %.6fs" % result['elapsed'])

    print("\n" + "=" * 70)
    print("[*] Anti-debugging scan complete")

    return 0

if __name__ == '__main__':
    sys.exit(main())

