import ctypes.util
import sys
import os

def get_function_address(lib_name, func_name):
    try:
        if sys.platform == 'linux':
            lib_path = ctypes.util.find_library(lib_name)
            if lib_path:
                lib = ctypes.CDLL(lib_path)
                func = getattr(lib, func_name, None)
                if func:
                    return ctypes.cast(func, ctypes.c_void_p).value
        elif sys.platform == 'win32':
            lib = ctypes.WinDLL(lib_name)
            func = getattr(lib, func_name, None)
            if func:
                return ctypes.cast(func, ctypes.c_void_p).value
    except Exception as e:
        return None
    return None

def python_hook_demo():
    original_open = open
    call_log = []
    def hooked_open(*args, **kwargs):
        call_log.append(f'open({args[0] if args else "?"})')
        print(f'  [HOOK] open() called: {args[0] if args else "?"}')
        return original_open(*args, **kwargs)
    return hooked_open, call_log, original_open

